import React from 'react';
import './WeatherMap.css';

const WeatherMap = ({ weather, loading, theme }) => {
  if (loading) return (
    <div className="card map-card">
      <div className="card-title">📍 Location Map</div>
      <div className="skeleton map-skeleton" />
    </div>
  );

  if (!weather) return null;

  const { lat, lon, name, country } = weather;

  // Free OpenStreetMap embed via openstreetmap.org — no API key needed
  const mapSrc = `https://www.openstreetmap.org/export/embed.html?bbox=${lon - 0.3}%2C${lat - 0.2}%2C${lon + 0.3}%2C${lat + 0.2}&layer=mapnik&marker=${lat}%2C${lon}`;

  return (
    <div className="card map-card">
      <div className="map-card-header">
        <div className="card-title">📍 Location Map</div>
        <div className="map-city-badge">{name}, {country}</div>
      </div>
      <div className="map-container">
        <iframe
          key={`${lat}-${lon}`}
          title="City Map"
          src={mapSrc}
          className="map-iframe"
          loading="lazy"
          scrolling="no"
          frameBorder="0"
        />
        <div className="map-coords">
          🌐 {lat?.toFixed(4)}°N, {lon?.toFixed(4)}°E
        </div>
      </div>
    </div>
  );
};

export default WeatherMap;
